//! Golden-vector parity tests against fixtures generated by the Go
//! controller (`controller/hack/goldenvec`; see tests/golden/README.md for
//! regeneration). These lock the bit-exact ES256 key derivation and the token
//! formats to the deployed Go behavior — a mismatch here means every deployed
//! credential would 401 on cutover.

use jumpstarter_controller_auth::go_compat::ecdsa_legacy::{
    derive_key_from_seed, hex_encode, key_scalars_hex,
};
use jumpstarter_controller_auth::go_compat::gorand::GoRand;
use serde::Deserialize;

// ---------------------------------------------------------------------------
// Fixture loading + minimal encoding helpers (kept local to avoid pulling
// base64/hex crates into the crate's dependency set just for tests).
// ---------------------------------------------------------------------------

fn golden(name: &str) -> String {
    let path = format!("{}/tests/golden/{name}", env!("CARGO_MANIFEST_DIR"));
    std::fs::read_to_string(&path).unwrap_or_else(|e| panic!("read {path}: {e}"))
}

fn b64_decode_with(alphabet: &[u8; 64], input: &str) -> Vec<u8> {
    let mut rev = [255u8; 256];
    for (i, c) in alphabet.iter().enumerate() {
        rev[*c as usize] = i as u8;
    }
    let raw: Vec<u8> = input
        .bytes()
        .filter(|b| *b != b'=')
        .map(|b| {
            let v = rev[b as usize];
            assert_ne!(v, 255, "invalid base64 char {:?} in {input:?}", b as char);
            v
        })
        .collect();
    let mut out = Vec::with_capacity(raw.len() * 3 / 4);
    for chunk in raw.chunks(4) {
        let mut acc: u32 = 0;
        for (i, v) in chunk.iter().enumerate() {
            acc |= (*v as u32) << (18 - 6 * i);
        }
        let n = match chunk.len() {
            4 => 3,
            3 => 2,
            2 => 1,
            _ => panic!("truncated base64 input {input:?}"),
        };
        for i in 0..n {
            out.push((acc >> (16 - 8 * i)) as u8);
        }
    }
    out
}

const STD_ALPHABET: &[u8; 64] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
const URL_ALPHABET: &[u8; 64] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_";

fn b64_std_decode(input: &str) -> Vec<u8> {
    b64_decode_with(STD_ALPHABET, input)
}

fn b64url_decode(input: &str) -> Vec<u8> {
    b64_decode_with(URL_ALPHABET, input)
}

fn b64url_encode_nopad(bytes: &[u8]) -> String {
    let mut out = String::with_capacity(bytes.len().div_ceil(3) * 4);
    for chunk in bytes.chunks(3) {
        let mut acc: u32 = 0;
        for (i, b) in chunk.iter().enumerate() {
            acc |= (*b as u32) << (16 - 8 * i);
        }
        let n = chunk.len() + 1;
        for i in 0..n {
            out.push(URL_ALPHABET[((acc >> (18 - 6 * i)) & 0x3f) as usize] as char);
        }
    }
    out
}

// ---------------------------------------------------------------------------
// derivation.json — the bit-exact key derivation
// ---------------------------------------------------------------------------

#[derive(Deserialize)]
struct DerivationFile {
    vectors: Vec<DerivationVector>,
}

#[derive(Deserialize)]
struct DerivationVector {
    name: String,
    controller_key_b64: String,
    sha256_hex: String,
    seed_int64: String,
    d_hex: String,
    x_hex: String,
    y_hex: String,
}

#[test]
fn derivation_vectors_match_go() {
    let file: DerivationFile = serde_json::from_str(&golden("derivation.json")).unwrap();
    assert!(
        file.vectors.len() >= 10,
        "expected at least 10 derivation vectors"
    );
    // Both signs of the intermediate int64 seed must be represented, or the
    // negative-seed normalization path is untested.
    assert!(file.vectors.iter().any(|v| v.seed_int64.starts_with('-')));
    assert!(file.vectors.iter().any(|v| !v.seed_int64.starts_with('-')));

    for v in &file.vectors {
        let seed = b64_std_decode(&v.controller_key_b64);

        // Cross-check the recorded intermediate values first so a failure
        // pinpoints the diverging stage.
        use sha2::{Digest, Sha256};
        let hash = Sha256::digest(&seed);
        assert_eq!(hex_encode(&hash), v.sha256_hex, "[{}] sha256", v.name);
        let int_seed = i64::from_be_bytes(hash[..8].try_into().unwrap());
        assert_eq!(
            int_seed.to_string(),
            v.seed_int64,
            "[{}] int64 seed",
            v.name
        );

        let key = derive_key_from_seed(&seed).unwrap();
        let (d, x, y) = key_scalars_hex(&key);
        assert_eq!(d, v.d_hex, "[{}] private scalar d", v.name);
        assert_eq!(x, v.x_hex, "[{}] public X", v.name);
        assert_eq!(y, v.y_hex, "[{}] public Y", v.name);
    }
}

// ---------------------------------------------------------------------------
// gorand.json — raw math/rand fixtures (Int63 + Read)
// ---------------------------------------------------------------------------

#[derive(Deserialize)]
struct GorandFile {
    cases: Vec<GorandCase>,
}

#[derive(Deserialize)]
struct GorandCase {
    seed: String,
    int63: Vec<String>,
    read_hex: String,
    read_split_hex: String,
}

#[test]
fn gorand_matches_go_fixtures() {
    let file: GorandFile = serde_json::from_str(&golden("gorand.json")).unwrap();
    assert!(file.cases.len() >= 8, "expected at least 8 gorand cases");

    for case in &file.cases {
        let seed: i64 = case.seed.parse().unwrap();

        let mut r = GoRand::new(seed);
        assert_eq!(case.int63.len(), 20, "[seed {seed}] fixture shape");
        for (i, want) in case.int63.iter().enumerate() {
            assert_eq!(
                r.int63().to_string(),
                *want,
                "[seed {seed}] Int63 #{i} mismatch"
            );
        }

        let mut r = GoRand::new(seed);
        let mut buf = [0u8; 64];
        r.read(&mut buf);
        assert_eq!(hex_encode(&buf), case.read_hex, "[seed {seed}] Read(64)");

        let mut r = GoRand::new(seed);
        let mut split = [0u8; 64];
        r.read(&mut split[..7]);
        r.read(&mut split[7..10]);
        r.read(&mut split[10..]);
        assert_eq!(
            hex_encode(&split),
            case.read_split_hex,
            "[seed {seed}] Read 7+3+54 (readVal/readPos persistence)"
        );
    }
}

// ---------------------------------------------------------------------------
// tokens.json — Go-signed tokens verify against Rust-derived keys
// ---------------------------------------------------------------------------

#[derive(Deserialize)]
struct TokensFile {
    internal: InternalToken,
    router: RouterTokens,
}

#[derive(Deserialize)]
struct InternalToken {
    seed_b64: String,
    issuer: String,
    audience: String,
    subject: String,
    token: String,
    claims: RegisteredClaims,
    jwks: Jwks,
}

#[derive(Deserialize)]
struct RouterTokens {
    key: String,
    tokens: Vec<RouterToken>,
}

#[derive(Deserialize)]
struct RouterToken {
    token: String,
    claims: RegisteredClaims,
}

#[derive(Deserialize, Debug, PartialEq)]
struct RegisteredClaims {
    iss: String,
    sub: String,
    aud: Vec<String>,
    exp: u64,
    #[serde(default)]
    nbf: Option<u64>,
    iat: u64,
    #[serde(default)]
    jti: Option<String>,
}

#[derive(Deserialize)]
struct Jwks {
    keys: Vec<Jwk>,
}

#[derive(Deserialize)]
struct Jwk {
    #[serde(rename = "use")]
    key_use: String,
    kty: String,
    kid: String,
    crv: String,
    alg: String,
    x: String,
    y: String,
}

/// 100 years, the fixed lifetime goldenvec configures via SetTokenLifetime.
const HUNDRED_YEARS_SECS: u64 = 100 * 365 * 24 * 3600;

#[test]
fn go_signed_internal_token_verifies_against_derived_key() {
    use jsonwebtoken::{decode, Algorithm, DecodingKey, Validation};
    use p256::elliptic_curve::sec1::ToEncodedPoint;

    let file: TokensFile = serde_json::from_str(&golden("tokens.json")).unwrap();
    let internal = &file.internal;

    let key = derive_key_from_seed(&b64_std_decode(&internal.seed_b64)).unwrap();
    let point = key.public_key().to_encoded_point(false);
    let decoding_key = DecodingKey::from_ec_components(
        &b64url_encode_nopad(point.x().unwrap()),
        &b64url_encode_nopad(point.y().unwrap()),
    )
    .unwrap();

    let mut validation = Validation::new(Algorithm::ES256);
    validation.set_issuer(&[&internal.issuer]);
    validation.set_audience(&[&internal.audience]);

    let data = decode::<RegisteredClaims>(&internal.token, &decoding_key, &validation)
        .expect("Go-signed internal token must verify against the Rust-derived public key");

    // Structural claim checks (op.go Token(): iss/sub/aud/iat/exp only).
    assert_eq!(data.claims, internal.claims);
    assert_eq!(data.claims.iss, internal.issuer);
    assert_eq!(data.claims.sub, internal.subject);
    assert_eq!(data.claims.aud, vec![internal.audience.clone()]);
    assert_eq!(data.claims.exp - data.claims.iat, HUNDRED_YEARS_SECS);
    assert_eq!(data.claims.nbf, None);
    assert_eq!(data.claims.jti, None);
    assert_eq!(data.header.alg, Algorithm::ES256);
}

#[test]
fn go_jwks_matches_derived_public_key() {
    use p256::elliptic_curve::sec1::ToEncodedPoint;

    let file: TokensFile = serde_json::from_str(&golden("tokens.json")).unwrap();
    let internal = &file.internal;
    assert_eq!(internal.jwks.keys.len(), 1);
    let jwk = &internal.jwks.keys[0];

    // Shape served by internal/oidc/op.go (kid = Signer.ID() = "default").
    assert_eq!(jwk.kty, "EC");
    assert_eq!(jwk.crv, "P-256");
    assert_eq!(jwk.alg, "ES256");
    assert_eq!(jwk.key_use, "sig");
    assert_eq!(jwk.kid, "default");

    let key = derive_key_from_seed(&b64_std_decode(&internal.seed_b64)).unwrap();
    let point = key.public_key().to_encoded_point(false);
    // go-jose serializes EC coordinates as fixed-width (32-byte) base64url.
    assert_eq!(b64url_decode(&jwk.x), point.x().unwrap().as_slice());
    assert_eq!(b64url_decode(&jwk.y), point.y().unwrap().as_slice());
}

#[test]
fn go_router_hs256_tokens_verify_with_shared_key() {
    use jsonwebtoken::{decode, Algorithm, DecodingKey, Validation};

    let file: TokensFile = serde_json::from_str(&golden("tokens.json")).unwrap();
    let router = &file.router;
    assert_eq!(router.tokens.len(), 2);

    let decoding_key = DecodingKey::from_secret(router.key.as_bytes());
    let mut validation = Validation::new(Algorithm::HS256);
    // Constants from internal/service/controller_service.go:866-874.
    validation.set_issuer(&["https://jumpstarter.dev/stream"]);
    validation.set_audience(&["https://jumpstarter.dev/router"]);

    for (i, t) in router.tokens.iter().enumerate() {
        let data = decode::<RegisteredClaims>(&t.token, &decoding_key, &validation)
            .unwrap_or_else(|e| panic!("router token #{i} must verify: {e}"));

        // Full Dial/Listen claim set: iss/sub/aud/exp/nbf/iat/jti.
        assert_eq!(data.claims, t.claims, "router token #{i}");
        assert_eq!(data.claims.iss, "https://jumpstarter.dev/stream");
        assert_eq!(data.claims.aud, vec!["https://jumpstarter.dev/router"]);
        assert!(data.claims.nbf.is_some(), "router token #{i} carries nbf");
        assert!(data.claims.jti.is_some(), "router token #{i} carries jti");
        assert_eq!(data.claims.nbf.unwrap(), data.claims.iat);
        assert_eq!(data.claims.exp - data.claims.iat, HUNDRED_YEARS_SECS);
        assert_ne!(data.claims.sub, "");
    }

    // The two tokens must be distinct rendezvous keys.
    assert_ne!(router.tokens[0].claims.sub, router.tokens[1].claims.sub);
}

// ---------------------------------------------------------------------------
// normalize_quote.json — username normalization + Go %q parity
//
// Generated from Go (stripOIDCPrefix / normalizeOIDCUsername / normalizeName in
// controller/internal/authorization/metadata.go; strconv.Quote for the quote
// vectors; the resource-name-mismatch fmt.Sprintf for the mismatch vectors).
// Covers multibyte, combining-mark, private-use, astral-plane, and
// control-character inputs where the Go regexp/byte-slice/unicode semantics
// diverge most from a naive Rust port.
// ---------------------------------------------------------------------------

use jumpstarter_controller_auth::normalize::{
    go_quote, normalize_name, normalize_oidc_username, strip_oidc_prefix,
};

#[derive(Deserialize)]
struct NormalizeQuoteFile {
    normalize: Vec<NormalizeVector>,
    quote: Vec<QuoteVector>,
    mismatch: Vec<MismatchVector>,
}

#[derive(Deserialize)]
struct NormalizeVector {
    input: String,
    strip: String,
    username: String,
    name: String,
}

#[derive(Deserialize)]
struct QuoteVector {
    input: String,
    quoted: String,
}

#[derive(Deserialize)]
struct MismatchVector {
    provided: String,
    username: String,
    message: String,
}

fn normalize_quote_fixture() -> NormalizeQuoteFile {
    serde_json::from_str(&golden("normalize_quote.json")).unwrap()
}

#[test]
fn normalize_vectors_match_go() {
    let file = normalize_quote_fixture();
    assert!(
        file.normalize.len() >= 40,
        "expected the full metadata_test.go corpus plus unicode cases"
    );
    for v in &file.normalize {
        assert_eq!(strip_oidc_prefix(&v.input), v.strip, "strip {:?}", v.input);
        assert_eq!(
            normalize_oidc_username(&v.input),
            v.username,
            "username {:?}",
            v.input
        );
        assert_eq!(normalize_name(&v.input), v.name, "name {:?}", v.input);
    }
}

#[test]
fn go_quote_vectors_match_go() {
    let file = normalize_quote_fixture();
    assert!(file.quote.len() >= 20, "expected the full quote corpus");
    for v in &file.quote {
        assert_eq!(go_quote(&v.input), v.quoted, "quote {:?}", v.input);
    }
}

/// The exact `resource name mismatch` message metadata.go:158-164 builds,
/// reconstructed from the public helpers (`context_attributes` composes these
/// three the same way; it is exercised directly with ASCII names in
/// `authorize.rs`, but the fixture's control-char operands can't traverse a
/// tonic ASCII metadata value, so parity is checked here at the string layer).
#[test]
fn resource_name_mismatch_message_matches_go() {
    let file = normalize_quote_fixture();
    assert!(!file.mismatch.is_empty());
    for v in &file.mismatch {
        let expected = normalize_oidc_username(&v.username);
        let message = format!(
            "resource name mismatch: provided {} but expected {} (derived from OIDC username {})",
            go_quote(&v.provided),
            go_quote(&expected),
            go_quote(&v.username),
        );
        assert_eq!(message, v.message, "mismatch provided={:?}", v.provided);
    }
}

// ---------------------------------------------------------------------------
// Helper self-tests
// ---------------------------------------------------------------------------

#[test]
fn base64_helpers_roundtrip() {
    assert_eq!(b64_std_decode("dGVzdA=="), b"test");
    assert_eq!(b64_std_decode(""), b"");
    assert_eq!(b64url_encode_nopad(b""), "");
    assert_eq!(b64url_encode_nopad(b"f"), "Zg");
    assert_eq!(b64url_encode_nopad(b"fo"), "Zm8");
    assert_eq!(b64url_encode_nopad(b"foo"), "Zm9v");
    assert_eq!(b64url_encode_nopad(&[0xfb, 0xff]), "-_8");
    assert_eq!(b64url_decode("-_8"), vec![0xfb, 0xff]);
    for input in [&b"hello world"[..], &[0u8, 255, 128, 7][..]] {
        assert_eq!(b64url_decode(&b64url_encode_nopad(input)), input);
    }
}
